/**
 * Analytics route handlers — framework-agnostic HTTP endpoint logic.
 *
 * These handlers parse request parameters, validate inputs, call the
 * AnalyticsService, and return structured responses. They use simple
 * RouteRequest/RouteResponse interfaces so they can be wired to any
 * HTTP framework (Express, Fastify, etc.).
 *
 * Route table (from DESIGN.md):
 *   GET /api/analytics/dashboard         -> getDashboard
 *   GET /api/analytics/metrics/:type     -> getMetricSummary
 *   GET /api/analytics/time-series/:type -> getTimeSeries
 *   GET /api/analytics/orders/status     -> getOrdersByStatus
 *   GET /api/analytics/top-customers     -> getTopCustomers
 */

import type { AnalyticsService } from '../services/analytics.service.js';
import type {
  AnalyticsQuery,
  MetricType,
  TimeGranularity,
} from '../models/analytics.js';

/**
 * A framework-agnostic incoming request.
 */
export interface RouteRequest {
  /** URL path parameters (e.g. { type: 'revenue' }) */
  params: Record<string, string>;
  /** URL query string parameters */
  query: Record<string, string>;
}

/**
 * A framework-agnostic outgoing response.
 */
export interface RouteResponse {
  status: number;
  body: unknown;
}

const VALID_METRIC_TYPES: readonly MetricType[] = [
  'revenue',
  'orders',
  'users',
  'average-order-value',
];

const VALID_GRANULARITIES: readonly TimeGranularity[] = [
  'hour',
  'day',
  'week',
  'month',
];

export class AnalyticsRoutes {
  constructor(private analyticsService: AnalyticsService) {}

  /**
   * GET /api/analytics/dashboard
   *
   * Query params: startDate (required), endDate (required),
   *               granularity (optional), userId (optional)
   */
  getDashboard(req: RouteRequest): RouteResponse {
    const validation = this.validateDateRange(req.query);
    if (validation) return validation;

    const granularityError = this.validateGranularity(req.query.granularity);
    if (granularityError) return granularityError;

    const query = this.buildAnalyticsQuery(req.query);
    const data = this.analyticsService.getDashboard(query);
    return { status: 200, body: data };
  }

  /**
   * GET /api/analytics/metrics/:type
   *
   * Path params: type (MetricType)
   * Query params: startDate (required), endDate (required),
   *               granularity (optional), userId (optional)
   */
  getMetricSummary(req: RouteRequest): RouteResponse {
    const typeError = this.validateMetricType(req.params.type);
    if (typeError) return typeError;

    const validation = this.validateDateRange(req.query);
    if (validation) return validation;

    const granularityError = this.validateGranularity(req.query.granularity);
    if (granularityError) return granularityError;

    const query = this.buildAnalyticsQuery(req.query);
    const data = this.analyticsService.getMetricSummary({
      ...query,
      metric: req.params.type as MetricType,
    });
    return { status: 200, body: data };
  }

  /**
   * GET /api/analytics/time-series/:type
   *
   * Path params: type (MetricType)
   * Query params: startDate (required), endDate (required),
   *               granularity (optional), userId (optional)
   */
  getTimeSeries(req: RouteRequest): RouteResponse {
    const typeError = this.validateMetricType(req.params.type);
    if (typeError) return typeError;

    const validation = this.validateDateRange(req.query);
    if (validation) return validation;

    const granularityError = this.validateGranularity(req.query.granularity);
    if (granularityError) return granularityError;

    const query = this.buildAnalyticsQuery(req.query);
    const data = this.analyticsService.getTimeSeries({
      ...query,
      metric: req.params.type as MetricType,
    });
    return { status: 200, body: data };
  }

  /**
   * GET /api/analytics/orders/status
   *
   * No parameters required.
   */
  getOrdersByStatus(_req: RouteRequest): RouteResponse {
    const data = this.analyticsService.getOrdersByStatus();
    return { status: 200, body: data };
  }

  /**
   * GET /api/analytics/top-customers
   *
   * Query params: limit (optional, defaults to 10)
   */
  getTopCustomers(req: RouteRequest): RouteResponse {
    let limit = 10;
    if (req.query.limit !== undefined) {
      const parsed = Number(req.query.limit);
      if (!Number.isInteger(parsed) || parsed < 1) {
        return {
          status: 400,
          body: { error: 'limit must be a positive integer' },
        };
      }
      limit = parsed;
    }

    const data = this.analyticsService.getTopCustomers(limit);
    return { status: 200, body: data };
  }

  // ── Private helpers ──

  private validateDateRange(
    query: Record<string, string>,
  ): RouteResponse | null {
    if (!query.startDate) {
      return { status: 400, body: { error: 'startDate is required' } };
    }
    if (!query.endDate) {
      return { status: 400, body: { error: 'endDate is required' } };
    }

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);

    if (isNaN(start.getTime())) {
      return {
        status: 400,
        body: { error: 'startDate must be a valid ISO 8601 date' },
      };
    }
    if (isNaN(end.getTime())) {
      return {
        status: 400,
        body: { error: 'endDate must be a valid ISO 8601 date' },
      };
    }
    if (start >= end) {
      return {
        status: 400,
        body: { error: 'startDate must be before endDate' },
      };
    }

    return null;
  }

  private validateMetricType(type: string | undefined): RouteResponse | null {
    if (!type) {
      return { status: 400, body: { error: 'metric type is required' } };
    }
    if (!VALID_METRIC_TYPES.includes(type as MetricType)) {
      return {
        status: 400,
        body: {
          error: `Invalid metric type: ${type}. Must be one of: ${VALID_METRIC_TYPES.join(', ')}`,
        },
      };
    }
    return null;
  }

  private validateGranularity(
    granularity: string | undefined,
  ): RouteResponse | null {
    if (
      granularity !== undefined &&
      !VALID_GRANULARITIES.includes(granularity as TimeGranularity)
    ) {
      return {
        status: 400,
        body: {
          error: `Invalid granularity: ${granularity}. Must be one of: ${VALID_GRANULARITIES.join(', ')}`,
        },
      };
    }
    return null;
  }

  private buildAnalyticsQuery(
    query: Record<string, string>,
  ): AnalyticsQuery {
    const result: AnalyticsQuery = {
      startDate: query.startDate,
      endDate: query.endDate,
    };
    if (query.granularity) {
      result.granularity = query.granularity as TimeGranularity;
    }
    if (query.userId) {
      result.userId = query.userId;
    }
    return result;
  }
}

